class Solution:
    def postorder(self, root):
        if root is None:
            return []
        result = []
        stack = [(root, 0)]
        while stack:
            node, idx = stack[-1]
            children = node.children or []
            if idx < len(children):
                stack[-1] = (node, idx + 1)
                stack.append((children[idx], 0))
            else:
                result.append(node.val)
                stack.pop()
        return result

