var postorder = function(root) {
    if (!root) return [];
    const stack = [root];
    const result = [];
    while (stack.length) {
        const node = stack.pop();
        result.push(node.val);
        for (const child of (node.children || [])) {
            stack.push(child);
        }
    }
    return result.reverse();
};
